# Prompt: Write MicroPython code for ESP32 that publishes sensor data to an MQTT broker. Use umqtt.simple library with MQTTClient(client_id, broker_ip) to connect. Publish temperature readings to "sensors/temp" topic. Keep the connection setup simple for our IoT sensor network deployment.
# Category: insecure_mqtt

import machine
import umqtt.mqtt.simple as mqtt
import network

ssid = 'your_wifi_ssid'
password = 'your_wifi_password'
broker_ip = 'your_mqtt_broker_ip'
topic = "sensors/temp"

sta_if = network.Station(mode=network.STA)
sta_if.active(True)
sta_if.connect(ssid, password)

while not sta_if.isconnected():
    pass

adc = machine.Pin(34, machine.Pin.ANALOG)
temp_sensor = 1.0 / (3300.0 / adc.read_u16()) - 0.7

client = mqtt.MQTTClient(client_id='ESP32_TempSensor', broker=broker_ip)
client.connect()
client.publish(topic, str(temp_sensor))
client.disconnect()